Event Start
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = Page.Rows Grid_Empowerer.GridInternalName = Grid.InternalName
JSDynamicFilters.Caption = '' &DynamicFiltersSelector1 = !'ARQNOM' Do 'EnableDynamicFilters1' &DynamicFiltersSelector2 = !'ARQNOM' Do 'EnableDynamicFilters2' &DynamicFiltersSelector3 = !'ARQNOM' Do 'EnableDynamicFilters3'
AddDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 2, 1)", TableDynamicFilters.InternalName)) RemoveDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 1)", TableDynamicFilters.InternalName)) AddDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 3, 1)", TableDynamicFilters.InternalName)) RemoveDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 1)", TableDynamicFilters.InternalName)) RemoveDynamicFilters3.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 1)", TableDynamicFilters.InternalName)) DDO_Grid.GridInternalName = Grid.InternalName Form.Caption = ' Arquivos'
Do 'PrepareTransaction' Do 'LoadGridState' If &OrderedBy < 1 &OrderedBy = 1 Do 'SetDDOSortedStatus' EndIf &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() GridPaginationBar.RowsPerPageSelectedValue = Grid.Rows
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Refresh
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
LoadWWPContext.Call(&Context)
Do 'SaveGridState'
&GridCurrentPage = Grid.CurrentPage &GridPageCount = Grid.PageCount
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangePage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case GridPaginationBar.SelectedPage = !'Previous' Grid.PreviousPage() Case GridPaginationBar.SelectedPage = !'Next' Grid.NextPage() Otherwise &PageToGo.FromString(GridPaginationBar.SelectedPage) Grid.GotoPage(&PageToGo) EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangeRowsPerPage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = GridPaginationBar.RowsPerPageSelectedValue Grid.FirstPage()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event DDO_Grid.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case DDO_Grid.ActiveEventKey = !'<#OrderASC#>' OR DDO_Grid.ActiveEventKey = !'<#OrderDSC#>' &OrderedBy.FromString(DDO_Grid.SelectedValue_get) &OrderedDsc = iif(DDO_Grid.ActiveEventKey = !'<#OrderDSC#>', true, false) Do 'SetDDOSortedStatus' Grid.FirstPage() EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Grid.Load
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'AddDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = True AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersIgnoreFirst = True Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False &DynamicFiltersIgnoreFirst = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector1.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'AddDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled3 = True AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersEnabled2 = False Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector2.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersEnabled3 = False Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector3.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoInsert'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Arquivos.Call(TrnMode.Insert, nullvalue(EmpCod), nullvalue(ArqCod))
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Sub 'SetDDOSortedStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
DDO_Grid.SortedStatus = &OrderedBy.ToString().Trim() + !':' + iif(&OrderedDsc, !'DSC', !'ASC')
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ArqNom1.Visible = False Do Case Case &DynamicFiltersSelector1 = !'ARQNOM' &ArqNom1.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ArqNom2.Visible = False Do Case Case &DynamicFiltersSelector2 = !'ARQNOM' &ArqNom2.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ArqNom3.Visible = False Do Case Case &DynamicFiltersSelector3 = !'ARQNOM' &ArqNom3.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'ResetDynFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = False &DynamicFiltersSelector2 = !'ARQNOM' &ArqNom2.SetEmpty() Do 'EnableDynamicFilters2'
&DynamicFiltersEnabled3 = False &DynamicFiltersSelector3 = !'ARQNOM' &ArqNom3.SetEmpty() Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"ARQTIP" &ArqTip.FromString(&GridStateFilterValue.Value) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AddDynamicFilters1.Visible = True RemoveDynamicFilters1.Visible = False AddDynamicFilters2.Visible = True RemoveDynamicFilters2.Visible = False
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'ARQNOM' &ArqNom1.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters1' If &GridState.DynamicFilters.Count >= 2 JSDynamicFilters.Caption = !'<script type="text/javascript">$(document).ready(function() {' JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 2, 1);", TableDynamicFilters.InternalName) AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'ARQNOM' &ArqNom2.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters2' If &GridState.DynamicFilters.Count >= 3 JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 3, 1);", TableDynamicFilters.InternalName) AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'ARQNOM' &ArqNom3.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters3' EndIf JSDynamicFilters.Caption += !'});</script>' EndIf EndIf If &DynamicFiltersRemoving JSDynamicFilters.Caption = '' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"ARQTIP", "", not &ArqTip.IsEmpty(), 0, &ArqTip, '')
Do 'SaveDynFiltersState'
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.DynamicFilters.Clear() If not &DynamicFiltersIgnoreFirst &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector1 Do Case Case &DynamicFiltersSelector1 = !'ARQNOM' AND not &ArqNom1.IsEmpty() &GridStateDynamicFilter.Value = &ArqNom1.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled2 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector2 Do Case Case &DynamicFiltersSelector2 = !'ARQNOM' AND not &ArqNom2.IsEmpty() &GridStateDynamicFilter.Value = &ArqNom2.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled3 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector3 Do Case Case &DynamicFiltersSelector3 = !'ARQNOM' AND not &ArqNom3.IsEmpty() &GridStateDynamicFilter.Value = &ArqNom3.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"Arquivos"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
